// @match        https://upsdrive.lightning.force.com/*
// @exclude      https://upsdrive.lightning.force.com/lightning/r/Contact/*
// @exclude      https://upsdrive.lightning.force.com/lightning/r/Dashboard/*
// @grant        GM_setValue
// @grant        GM_getValue
// @grant        GM_registerMenuCommand
// @grant        GM_addStyle
// @grant        GM_deleteValue
// @grant        GM_addValueChangeListener
// @run-at       document-idle
// @license      Proprietary; authorized for internal company business processes only; modification or redistribution is strictly prohibited.
// @updateURL    https://github.com/Jerry199022/Work-Release/raw/refs/heads/main/CEC.user.js
